import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"“妖器”银刃","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/“妖器”银刃.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/“妖器”银刃.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/“妖器”银刃.md"};function b(d,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"妖器-银刃",tabindex:"-1"},[n("“妖器”银刃 "),r("a",{class:"header-anchor",href:"#妖器-银刃","aria-label":'Permalink to "“妖器”银刃"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌031")])])],-1),s('<h1 id="妖器-银刃-1" tabindex="-1">“妖器”银刃 <a class="header-anchor" href="#妖器-银刃-1" aria-label="Permalink to &quot;“妖器”银刃&quot;">​</a></h1><p>“妖器”银刃<br> 分类：投掷武器<br> 描述：<br> 某杀人鬼小姐在伦敦游猎时所使用的武器，本体为一块精致的怀表，只要本体没被摧毁，就能够消耗魔力来凝聚出投掷用的飞刀，银刃并不是代指拥有的材质，而是代表飞刀上闪耀着的凛冽寒光</p><p>初步掌握<br> 价格：D+500<br> 描述：<br> 虽然听起来很麻烦，但操作起来很简单的，输入魔力，想象出飞刀的外形，看，很简单吧，现在就只需要扔出去就好了<br> 效果：<br> 该武器会占据持有者的1点意志池上限。<br> 自由动作消耗1点魔力，在你的手中凝聚出一把持续一轮，体积1的银刃</p><p>凝聚而出的银刃拥有6L武器伤害，具有【破甲5】【法破】特性，造成物理-穿刺伤害，在投掷的一瞬间时可以分化为三柄，如【短点射】一般速射。</p><p>小有所成（差价升级）<br> 价格：C+1000<br> 描述：是不是觉得一把飞刀压制力不够呢，其实很简单，还记得之前构造一把的配比吗，等比例的增加就好了。当然不要忘了，眼要准，手要稳，力度要狠。<br> 效果：<br> 该武器会占据持有者的1点意志池上限。<br> 自由动作消耗1点魔力，在你的手中凝聚出一把持续一轮，体积1的银刃</p><p>凝聚而出的银刃拥有，11L的武器伤害与【破甲5】【法破】的特性。</p><p>投掷攻击前可以消耗2点魔力，额外生成至多4把银刃，这些银刃在投掷时会幻化成复数，这会令你这次进行的投掷攻击速射等级提升为【连射】。</p><p>投掷攻击前可以消耗1点魔力，这次攻击可以同时对攻击范围内的另一个目标投掷银刃造成伤害。</p><p>投掷攻击前可以消耗4点魔力，令银刃的【破甲5】改变为【传奇力量】*5点破甲</p><p>登堂入室（差价升级）<br> 价格：B+2000<br> 描述：<br> 最后再教你一个小技巧，将魔力的联系想象为一根根丝线连接在飞刀之间，这样你就能随心的操控它出现在你想出现的任何地方了。还有一个温馨提示，做好魔力管理，方便在任何时候都留有余力。加油活下去吧，继任者～<br> 效果：<br> 该武器会占据持有者的1点意志池上限。<br> 自由动作消耗1点魔力，在你的手中凝聚出一把持续一轮，体积1的银刃</p><p>凝聚而出的银刃拥有，18L的武器伤害与【破甲5】【法破】和【9加骰】的特性</p><p>投掷攻击前可以消耗1点魔力，额外生成至多9把银刃，这些银刃在投掷时会幻化成复数，这会令你这次进行的投掷攻击速射等级提升为【连射】，并使这次攻击加骰等级提升一级（至多为8加骰）。</p><p>投掷攻击前可以消耗1点魔力，这次攻击可以同时对攻击范围内的另一个目标投掷银刃造成伤害。</p><p>投掷攻击前可以消耗1点魔力，令本次攻击中，银刃带来的破甲变为【传奇力量】*5点破甲</p><p>投掷攻击前可以消耗3点魔力，令本次攻击获得C级的传送攻击效果</p><p>投掷攻击前可以消耗3点魔力，令本次攻击的射程提升【传奇敏捷】*10m的射程</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
